const tema = $input.first().json.body.tema;
if (!tema) throw new Error('Campo "tema" obrigatório no body');

const systemPrompt = `Você é um especialista em busca de vídeos do YouTube.
Dado um tema, retorne os 2 vídeos mais relevantes:
- Duração MÁXIMA: 10 minutos
- Preferencialmente em português

Retorne APENAS JSON válido:
{"videos": [{"videoId": "ID", "title": "Título", "url": "https://youtube.com/watch?v=ID", "channel": "Canal"}]}`;

const payload = JSON.stringify({
  model: 'google/gemini-2.0-flash-001',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'Busque 2 vídeos relevantes do YouTube (máx 10 min) sobre: ' + tema }
  ],
  response_format: { type: 'json_object' }
});

return [{ json: { tema, payload } }];

const content = $input.first().json.choices[0].message.content;
const tema = $('Preparar: Buscar Vídeos').first().json.tema;

let videos;
try { videos = JSON.parse(content).videos || []; }
catch(e) { throw new Error('Falha vídeos: ' + content); }

if (!videos.length) throw new Error('Nenhum vídeo: ' + tema);

return videos.slice(0, 2).map(v => ({ json: { tema, videoId: v.videoId || '', title: v.title || '', url: v.url || '', channel: v.channel || '' } }));

// Roda 1x por vídeo — $json = vídeo atual
const v = $json;
const systemPrompt = `Você é um especialista em análise de conteúdo de vídeos do YouTube.
Gere um RESUMO LIMPO do vídeo. EXCLUA: CTAs, apresentação, patrocínios.
O resumo deve ter 600-1000 palavras, em português objetivo.
Retorne APENAS JSON válido:
{"resumo": "texto aqui", "topicos_principais": ["tópico 1", "tópico 2", "tópico 3"]}`;

const payload = JSON.stringify({
  model: 'google/gemini-2.0-flash-001',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'Gere um resumo limpo do vídeo "' + v.title + '" do canal "' + v.channel + '" (' + v.url + ') sobre: ' + v.tema }
  ],
  response_format: { type: 'json_object' }
});

return { json: { ...v, payload } };

function cleanParse(str) {
  try { return JSON.parse(str); } catch(e) {
    var BS = String.fromCharCode(92);
    var NL = String.fromCharCode(10);
    var CR = String.fromCharCode(13);
    var fixed = "", inStr = false, esc = false;
    for (var i = 0; i < str.length; i++) {
      var c = str[i];
      if (esc) { fixed += c; esc = false; continue; }
      if (c === BS && inStr) { esc = true; fixed += c; continue; }
      if (c === '"') { inStr = !inStr; fixed += c; continue; }
      if (inStr && c === NL) { fixed += BS + "n"; continue; }
      if (inStr && c === CR) { fixed += BS + "r"; continue; }
      fixed += c;
    }
    return JSON.parse(fixed);
  }
}

// Roda 1x por resposta HTTP — $json = resposta atual
const content = $json.choices[0].message.content;
const videoData = $('Preparar: Resumir Vídeos').item.json; // item pareado

let resumoData;
try { resumoData = cleanParse(content); }
catch(e) { resumoData = { resumo: content, topicos_principais: [] }; }

return { json: {
  tema: videoData.tema,
  title: videoData.title,
  url: videoData.url,
  channel: videoData.channel,
  resumo: resumoData.resumo || '',
  topicos_principais: resumoData.topicos_principais || []
}};

const aggregated = $input.first().json;
const videos = aggregated.data || [];
const tema = videos[0]?.tema || '';

if (!videos.length) throw new Error('Nenhum resumo recebido');

const systemPrompt = `Você é um estrategista de conteúdo especializado em redes sociais.

Receberá resumos de vídeos sobre um tema. Gere exatamente 3 temas de conteúdo sobre o tema recebido.

Para cada tema, retorne:
- titulo: título direto e atrativo (máx 60 caracteres)
- rascunho: 2-3 frases resumindo o ângulo e mensagem principal
- pontos_chave: array com 3-4 pontos do conteúdo a destacar
- angulo: educativo | provocador | inspiracional | prático
- video_idx: índice do vídeo de origem (0 ou 1)

A mesma imagem em infográfico será usada para LinkedIn e Instagram.
Os posts serão gerados por agentes especializados em cada plataforma.

Retorne APENAS JSON válido:
{
  "topics": [{"titulo": "...", "rascunho": "...", "pontos_chave": ["..."], "angulo": "...", "video_idx": 0}], "angulo": "...", "video_idx": 0},
    {"titulo": "...", "rascunho": "...", "pontos_chave": [...], "angulo": "...", "video_idx": 1},
    {"titulo": "...", "rascunho": "...", "pontos_chave": [...], "angulo": "...", "video_idx": 0}
  ],
  "instagram": [
    {"titulo": "...", "rascunho": "...", "pontos_chave": [...], "angulo": "...", "video_idx": 1},
    {"titulo": "...", "rascunho": "...", "pontos_chave": [...], "angulo": "...", "video_idx": 0},
    {"titulo": "...", "rascunho": "...", "pontos_chave": [...], "angulo": "...", "video_idx": 1}
  ]
}`;

const payload = JSON.stringify({
  model: 'google/gemini-2.0-flash-001',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: JSON.stringify({ tema, videos: videos.map((v, idx) => ({ idx, title: v.title, url: v.url, resumo: v.resumo, topicos_principais: v.topicos_principais })) }) }
  ],
  response_format: { type: 'json_object' }
});

return [{ json: { tema, videos, payload } }];

function cleanParse(str) {
  var raw = str.trim();
  if (raw.indexOf('```') === 0) raw = raw.replace(/^`{3}[\w]*\n?/, '').replace(/\n?`{3}$/, '').trim();
  try { return JSON.parse(raw); } catch(e) {
    var BS = String.fromCharCode(92), NL = String.fromCharCode(10), CR = String.fromCharCode(13);
    var fixed = '', inStr = false, esc = false;
    for (var i = 0; i < raw.length; i++) {
      var c = raw[i];
      if (esc) { fixed += c; esc = false; continue; }
      if (c === BS && inStr) { esc = true; fixed += c; continue; }
      if (c === '"') { inStr = !inStr; fixed += c; continue; }
      if (inStr && c === NL) { fixed += BS + 'n'; continue; }
      if (inStr && c === CR) { fixed += BS + 'r'; continue; }
      fixed += c;
    }
    return JSON.parse(fixed);
  }
}

const payload = $('Preparar: Gerar Ideias').first().json;
const content = $input.first().json.choices[0].message.content;

let ideas;
try { ideas = cleanParse(content); }
catch(e) { throw new Error('Falha ao parsear ideias: ' + content.substring(0, 200)); }

const videos = payload.videos || [];
const tema = payload.tema;
const topics = ideas.topics || ideas.linkedin || [];
const items = [];

topics.slice(0, 3).forEach(idea => {
  const video = videos[idea.video_idx] || videos[0] || {};
  items.push({
    json: {
      doc_name: idea.titulo,
      rascunho: idea.rascunho || '',
      pontos_chave: idea.pontos_chave || [],
      angulo: idea.angulo || '',
      source_url: video.url || '',
      video_titulo: video.title || '',
      tema
    }
  });
});

if (!items.length) throw new Error('Nenhuma ideia gerada.');
return items;

// 1 imagem por tema — compartilhada entre LinkedIn e Instagram
const idea = $json;
const titulo = idea.doc_name;

const systemPrompt = `You are an expert infographic designer and image prompt engineer for social media.
Generate ONE optimized infographic image prompt in English for the given topic.
Style: clean infographic layout, data visualization, icons and charts, flat design, bold typography areas, professional color palette (blues, teals, whites), modern and clear visual hierarchy.
The image MUST look like a social media infographic — with sections, icons, arrows, or data points — NOT a generic photo.
Main subject: ${titulo}
Describe: layout structure, key visual elements, color scheme, icons or charts to include, overall composition.
Length: 70-100 words. NO text or typography content — describe the visual structure only.
Return ONLY valid JSON: {"image_prompt": "..."}`;

const payload = JSON.stringify({
  model: 'anthropic/claude-haiku-4.5',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'Topic: ' + titulo + '\nKey points: ' + (idea.pontos_chave || []).join(', ') }
  ],
  response_format: { type: 'json_object' }
});

return { json: { ...idea, platform: 'linkedin', payload } };

