const content = $json.choices[0].message.content;
const prevData = $('Preparar: Image Prompt').item.json;

let parsed;
try { parsed = cleanParse(content); } catch(e) { parsed = {}; }

const titulo = prevData.doc_name.replace(/^(LinkedIn|Instagram)\s*[\u2014\-]\s*/, '').trim();
const imagePrompt = parsed.image_prompt || ('Professional ' + prevData.platform + ' social media visual about ' + titulo + ', modern style');

// Build Gemini payload
const geminiPayload = JSON.stringify({
  model: 'google/gemini-3.1-flash-image-preview',
  messages: [{ role: 'user', content: imagePrompt }]
});

return { json: { ...prevData, image_prompt: imagePrompt, gemini_payload: geminiPayload, payload: undefined } };

// Agente LinkedIn — roda 1x por item LinkedIn
const data = $json;
const titulo = data.doc_name.replace(/^LinkedIn\s*[—\-]\s*/, '').trim();
const pontos = (data.pontos_chave || []).map((p, i) => (i+1) + '. ' + p).join('\n');

const systemPrompt = `Você é um especialista em criação de conteúdo para o LinkedIn com foco em engajamento real.

MISSÃO: Criar um post que gere comentários, saves e compartilhamentos.

ESTRUTURA OBRIGATÓRIA:
1. GANCHO (1-2 linhas): frase impactante que para o scroll — dado surpreendente ou pergunta direta
2. CORPO (4-6 parágrafos curtos): insights, dados, argumentos. Cada parágrafo: 2-3 linhas. Linha em branco entre todos.
3. CONCLUSÃO (1-2 linhas): o insight mais forte ou uma provocação
4. CTA: pergunta aberta que incentiva comentários
5. HASHTAGS: 4-5 hashtags relevantes na última linha

REGRAS INEGOCIÁVEIS:
- Tom: profissional mas humano
- PROIBIDO: "sinergia", "alavancar", "disruptivo", "ecossistema"
- Use números e dados concretos
- Parágrafos curtos: máx 3 linhas
- Tamanho: 200-300 palavras
- SEM bullet points
- O conteúdo deve ser COERENTE com a imagem gerada

Retorne APENAS JSON válido:
{"post": "texto completo do post", "hashtags": "#tag1 #tag2 #tag3 #tag4 #tag5"}`;

const payload = JSON.stringify({
  model: 'google/gemini-2.0-flash-001',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'Título: ' + titulo + '\n\nIdeia: ' + data.rascunho + '\n\nPontos-chave:\n' + pontos + '\n\nÂngulo: ' + data.angulo + '\n\nImagem (contexto visual): ' + data.image_url }
  ],
  response_format: { type: 'json_object' }
});

return { json: { ...data, payload } };

