const content = $json.choices[0].message.content;
const prevData = $('Preparar: Agente LinkedIn').item.json;

let parsed;
try { parsed = cleanParse(content); }
catch(e) { throw new Error('Falha LinkedIn: ' + String(content).slice(0, 100)); }

const post = parsed.post || '';
const hashtags = parsed.hashtags || '';
const postContent = post + (hashtags ? '\n\n' + hashtags : '');

return { json: { ...prevData, post_content: postContent, payload: undefined } };

// Agente Instagram — post único, tom Instagram
const data = $json;
const titulo = data.doc_name.replace(/^Instagram\s*[—\-]\s*/, '').trim();
const pontos = (data.pontos_chave || []).map((p, i) => (i+1) + '. ' + p).join('\n');

const systemPrompt = `Você é um especialista em criação de conteúdo para o Instagram com foco em conexão humana e engajamento emocional.

MISSÃO: Criar um post que gere saves, comentários e compartilhamentos nas stories.

ESTRUTURA OBRIGATÓRIA:
1. GANCHO (1-2 linhas): frase que para o scroll — pessoal, curiosa ou impactante. Pode começar com emoji.
2. CORPO (4-6 parágrafos curtos): história, insight ou reflexão. Tom próximo, como se fosse uma conversa. Linha em branco entre parágrafos.
3. CONCLUSÃO (1-2 linhas): o ensinamento ou provocação que fica na cabeça
4. CTA: pergunta leve que convida o seguidor a comentar ou salvar
5. HASHTAGS: 12-15 hashtags na última linha

DIFERENÇAS DO LINKEDIN:
- Tom: pessoal, quente, autêntico — fale como uma pessoa, não como uma empresa
- Use emojis com moderação (2-4 no post inteiro)
- Histórias curtas e concretas funcionam melhor que dados frios
- Frases mais curtas, ritmo mais dinâmico
- Tamanho: 150-250 palavras
- SEM bullet points
- PROIBIDO: linguagem corporativa, termos técnicos sem explicação

Retorne APENAS JSON válido:
{"post": "texto completo do post com emojis e quebras de linha", "hashtags": "#tag1 #tag2 #tag3 ..."}
`;

const payload = JSON.stringify({
  model: 'google/gemini-2.0-flash-001',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'Título: ' + titulo + '\n\nIdeia: ' + data.rascunho + '\n\nPontos-chave:\n' + pontos + '\n\nÂngulo: ' + data.angulo + '\n\nImagem (contexto visual): ' + data.image_url }
  ],
  response_format: { type: 'json_object' }
});

return { json: { ...data, payload } };

