const content = $json.choices[0].message.content;
const prevData = $('Preparar: Agente Instagram').item.json;

let parsed;
try { parsed = cleanParse(content); }
catch(e) { throw new Error('Falha Instagram: ' + String(content).slice(0, 100)); }

const post = parsed.post || '';
const hashtags = parsed.hashtags || '';
const postContent = post + (hashtags ? '\n\n' + hashtags : '');

return { json: { ...prevData, post_content: postContent, hashtags, payload: undefined } };

const pageId = $json.id;
const postData = $('Merge Posts').item.json;

const caption = postData.post_content || '';
const hashtags = postData.hashtags || '';
const imageUrl = postData.image_url || '';

const fullCaption = hashtags ? caption + '\n\n' + hashtags : caption;

const blocks = [
  {
    object: 'block',
    type: 'paragraph',
    paragraph: {
      rich_text: [{ type: 'text', text: { content: fullCaption.substring(0, 2000) } }]
    }
  }
];

if (imageUrl) {
  blocks.push({
    object: 'block',
    type: 'image',
    image: { type: 'external', external: { url: imageUrl } }
  });
}

return {
  json: {
    page_id: pageId,
    payload: JSON.stringify({ children: blocks }),
    platform: postData.platform,
    doc_name: postData.doc_name,
  }
};

const geminiResp = $json;
const prevData = $('Parsear + Gerar URL Imagem').item.json;

const images = geminiResp.choices &&
               geminiResp.choices[0] &&
               geminiResp.choices[0].message &&
               geminiResp.choices[0].message.images;

if (!images || !images[0] || !images[0].image_url) {
  throw new Error('Gemini nao retornou imagem: ' + JSON.stringify(geminiResp).substring(0, 200));
}

const dataUrl = images[0].image_url.url || '';
const base64Data = dataUrl.includes(',') ? dataUrl.split(',')[1] : dataUrl;

const imgurPayload = JSON.stringify({ image: base64Data, type: 'base64' });

return { json: { ...prevData, imgur_payload: imgurPayload } };

const imgurResp = $json;
const prevData = $('Parsear Base64').item.json;

if (!imgurResp.success) {
  throw new Error('Imgur falhou: ' + JSON.stringify(imgurResp).substring(0, 200));
}

const imageUrl = imgurResp.data.link;

return { json: { ...prevData, image_url: imageUrl, imgur_payload: undefined } };

// Expande 3 temas → 6 itens (linkedin + instagram por tema)
const items = $input.all();
const output = [];

items.forEach(item => {
  const base = item.json;
  // LinkedIn version
  output.push({ json: {
    ...base,
    platform: 'linkedin',
    doc_name: 'LinkedIn — ' + base.doc_name
  }});
  // Instagram version — mesma imagem
  output.push({ json: {
    ...base,
    platform: 'instagram',
    doc_name: 'Instagram — ' + base.doc_name
  }});
});

return output;
